mapper.select:
	/* mapper.terms.com.erns.coching.TermsDAO.getList */

	SELECT B.* FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

				, CD1.CODE_NAME
				, CD1.ETC1
				, CD1.ETC5
			FROM T_TERMS_INF AA
				JOIN T_CODE_INF CD1
					ON CD1.GRP_CODE = 'CH004' AND CD1.ETC5 = UPPER(#{locale}) AND AA.TERMS_CD = CD1.CODE



					AND CD1.ETC1 = #{localeTermsCd, jdbcType=VARCHAR}



		    		#{item, jdbcType=VARCHAR}


			ORDER BY AA.RGT_DTTM DESC
		) A

    ) B WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

	/* mapper.terms.com.erns.coching.TermsDAO.getListCount */

	SELECT
		COUNT(*)
	FROM T_TERMS_INF AA
		JOIN T_CODE_INF CD1
			ON CD1.GRP_CODE = 'CH004' AND CD1.ETC5 = UPPER(#{locale, jdbcType=VARCHAR}) AND AA.TERMS_CD = CD1.CODE



			AND CD1.ETC1 = #{localeTermsCd, jdbcType=VARCHAR}



    		#{item, jdbcType=VARCHAR}

	/* mapper.terms.com.erns.coching.TermsDAO.load */

	SELECT

		, CD1.CODE_NAME
		, CD1.ETC1
		, CD1.ETC5
	FROM T_TERMS_INF AA
		JOIN T_CODE_INF CD1
			ON CD1.GRP_CODE = 'CH004' AND CD1.ETC5 = UPPER(#{locale}) AND AA.TERMS_CD = CD1.CODE

		AND AA.USE_YN 	= 'Y'

			AND AA.TERMS_CD = #{termsCd, jdbcType=VARCHAR}


			AND CD1.ETC1 = #{localeTermsCd, jdbcType=VARCHAR}


    		#{item, jdbcType=VARCHAR}

	/* mapper.terms.com.erns.coching.TermsDAO.getVersionList */

	SELECT VERSION
	FROM T_TERMS_INF AA
		JOIN T_CODE_INF CD1
			ON CD1.GRP_CODE = 'CH004' AND CD1.ETC5 = UPPER(#{locale, jdbcType=VARCHAR}) AND AA.TERMS_CD = CD1.CODE


			AND AA.TERMS_CD = #{termsCd, jdbcType=VARCHAR}


			AND CD1.ETC1 = #{localeTermsCd, jdbcType=VARCHAR}


    		#{item, jdbcType=VARCHAR}


	ORDER BY RGT_DTTM DESC
